var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"솔직히 놀랐습니다. 설마 여기까지 올 거라고는 생각 못했거든요.","JPN":"正直、驚きました。まさかここまで辿り着くとは思っていませんでしたから。","ENG":"I was honestly surprised. I didn't think you'd make it here.","TWN":"說實話，我很驚訝。沒想到你們真的會走到這一步。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"부사장님…? 여긴 대체 어떻게 오신 거예요?","JPN":"副社長……？　ここにはどうやって？","ENG":"Vice President...? How did you come all the way here?","TWN":"副總……？你怎麼來了？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…아니. 이 사람 저 사람 본 시점에서 아무 의미 없는 질문이려나.","JPN":"……いや、色んな人たちに会っているわけだし、野暮な質問でしたね。","ENG":"...Well. I guess it's not really worth asking considering all the others we've encountered so far.","TWN":"……不，從之前遇到的那些人看來，這個問題根本沒意義吧？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"뭘 좀 아시는군요. 저희가 재회의 기쁨을 만끽할 만큼 각별한 사이는 아니죠.","JPN":"よくおわかりで。私たちは再会の喜びを分かち合うほど、親しい仲でもありませんよね。","ENG":"Glad we can skip that part. We're not really close enough to rejoice in reuniting.","TWN":"悠菲很聰明呢。我們的關係沒有熟到能享受重逢的喜悅吧。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐래. 그냥 넘어간다는 소리도 아니거든요?","JPN":"だからといって、なかったことにしてもいいとは言ってませんからね。","ENG":"That doesn't mean we can skip all the questions.","TWN":"說什麼呢。我可沒想就這麼算了？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"타이탄 씨나 알트 소대도 그렇고. 대체 다른 분들에게 무슨 말을 하신 거예요?","JPN":"タイタンさんやアルト小隊、そして他の方々に、いったい何を吹き込んだんですか？","ENG":"Titan, and ALT Squad. What on earth did you tell them?","TWN":"泰坦先生和阿爾特小隊也是，你到底對他們說了什麼？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"무슨 말씀인지 도통 모르겠군요. 제가 처음부터 말씀드리지 않았습니까?","JPN":"何のことでしょう。初めから言いましたよね？","ENG":"I don't know what you're talking about.","TWN":"我完全不明白你在說什麼。我不是從一開始就已經說明了嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유피 양이 해결해야 할 <color=#ffd34c>과제</color>가 있다고.","JPN":"ユピさんが解決すべき<color=#ffd34c>課題</color>があると。","ENG":"However, I did tell you in the beginning, that there is a <color=#ffd34c>task</color> you have to complete.","TWN":"悠菲有一個<color=#ffd34c>任務</color>要完成。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그러니까, 지금까지 전부 코핀 컴퍼니의 입사 시험이었다?","JPN":"つまり、これは全部コフィンカンパニーへの入社試験だったってことですか？","ENG":"You're meaning to say that this was all part of the test to get into Coffin Company?","TWN":"所以說，到目前為止這一切都是科芬公司的入職測試嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"경영진으로서 회사에 범죄자를 받아들이는 게 어디 쉬운 일이겠습니까.","JPN":"副社長として会社に犯罪者を受け入れることは簡単なことではありません。","ENG":"As an executive, I can't accept an individual with a criminal record without a good reason.","TWN":"作為管理層，接納罪犯進入公司可不是件容易的事。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"레이첼 양의 추천이 있다고 한들, 유피 양이 어떤 사람인지 알아볼 필요가 있었죠.","JPN":"あのレイチェルさんからの推薦だったとはいえ、ユピさんがどんな方なのかを調べる必要がありました。","ENG":"Even though Rachel recommended you, I still needed to see what kind of person you were.","TWN":"即便有瑞秋的推薦，也有必要了解一下悠菲是怎樣的人。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"축하드립니다, 유피 양. 시험은 합격이에요.","JPN":"おめでとうございます、ユピさん。あなたは合格しました。","ENG":"Congratulations, Yuppie. You passed the test.","TWN":"恭喜你，悠菲。你通過了測試。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"전부 끝났으니 상자를 돌려주고 떠나시죠. 뒷일은 제가 잘 처리하겠습니다.","JPN":"試験は終了したので、箱をこちらに返し、島を離れてください。後始末は私にお任せを。","ENG":"Since it's all over, you are to return the chest and leave. I'll take care of the rest.","TWN":"既然都結束了，把箱子還給我，然後你就可以離開了。後面的事我會處理好的。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"있죠, 부사장님. 아무리 제가 을이라도 이렇게 막 나가시면 안 되죠.","JPN":"あの、副社長。いくら私の立場が低いとはいえ、こんなやり方はどうかと思います。","ENG":"You know, Vice President. You may be in a higher position than me, but this is too much.","TWN":"副總……雖然我只是個小員工，但你也不能這樣呼來喚去吧。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이거 하나 얻겠다고 얼마나 고생했는지 아세요?","JPN":"これを手に入れるために、いったいどれだけ苦労したかわかりますか？","ENG":"Do you know how much I went through to get this one thing?","TWN":"為了得到這個箱子，你知道我有多辛苦嗎……？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞아, 부사장 아줌마. 게임은 치사하면 안 된다구.","JPN":"そうだよ、副社長のおばさん。ゲームは正々堂々勝負しなきゃ。","ENG":"Yeah, Vice President. You should play fair and square.","TWN":"沒錯，副總大嬸。玩遊戲可不能耍賴喔。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"잘 생각하시죠, 유피 양. 제 앞에서의 모든 행실은 처우협의 과정에 반영됩니다.","JPN":"ユピさん、よく考えて行動してください。あなたの言動はすべて、これからの処遇協議の過程に反映されるんですよ。","ENG":"Think carefully, Yuppie. Whatever you do in my presence will be taken into account for your contract negotiation.","TWN":"好好考慮一下，悠菲。你在我面前的所有行為都會反映在待遇協商的結果裡。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"역시 싫어요.","JPN":"やっぱり嫌です。","ENG":"No.","TWN":"不要。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"제대로 된 설명 하나 없이 이대로 가라고 해도 납득할 수 있을 리가 없잖아요.","JPN":"ちゃんとした説明もなしに、このまま帰れと言われても、納得できるはずがありません。","ENG":"You can't expect me to just accept all that without a proper explanation.","TWN":"不給我一個合理的解釋就讓我走，這樣做我不接受！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…예상대로군요. 그리 쉽게 포기할 인간이었다면 여기에 오지도 못했겠죠.","JPN":"……やはりそうですか。そう簡単に諦めるような人なら、そもそもここまで来られるはずがありませんものね。","ENG":"...Of course. You wouldn't have made it this far if you were someone who gave up easily.","TWN":"……果然不出所料。如果你是容易放棄的人，也不會來到這裡了吧。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"유감입니다.","JPN":"とても残念です。","ENG":"But that's a shame.","TWN":"真遺憾。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"히이이익?!","JPN":"ひいい！？","ENG":"Eeeek!","TWN":"欸欸欸？!"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"저… 저 사람. 방금 절 베려 했어요. 절 죽이려 했다고요!","JPN":"あの……あの人、私に斬りかかりましたよね。私を殺そうとしましたよね！？","ENG":"S-she... just tried to cut me. She tried to kill me!","TWN":"那……那個人，剛剛想砍我。她想殺了我！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"엄살 떨지 마시죠. 칼등에는 맞아도 안 죽습니다.","JPN":"大袈裟です。峰打ちですから、死にはしません。","ENG":"No need to exaggerate this. You won't die from getting hit by the back of a knife.","TWN":"別裝了。就算被刀背打到也不會死的。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"칼등으로는 친다는 거잖아! 이거 엄연한 사내폭력인 거 몰라요?","JPN":"結局殴るってことでしょう？　こんなの社内暴力です！","ENG":"You were still going to hit me with it! That's workplace violence!","TWN":"用刀背打也是打啊！你不知道這是明顯的職場暴力嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};